CREATE TABLE "user" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "email" VARCHAR NOT NULL,
  "hashed_password" VARCHAR,
  "is_active" BOOLEAN NOT NULL,
  "role" userrole NOT NULL,
  "preferred_language" languagecode NOT NULL DEFAULT 'en'
);

CREATE TABLE "language" (
  "code" languagecode PRIMARY KEY,
  "name" VARCHAR NOT NULL,
  "native_name" VARCHAR NOT NULL,
  "is_active" BOOLEAN NOT NULL
);

CREATE TABLE "customerprofile" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "user_id" INTEGER NOT NULL,
  "first_name" VARCHAR NOT NULL,
  "last_name" VARCHAR,
  "phone" "VARCHAR(20)" NOT NULL,
  "date_of_birth" DATE,
  "gender" VARCHAR
);

CREATE TABLE "adminprofile" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "user_id" INTEGER NOT NULL,
  "first_name" VARCHAR NOT NULL,
  "last_name" VARCHAR,
  "phone" "VARCHAR(20)" NOT NULL,
  "employee_code" VARCHAR,
  "department" VARCHAR
);

CREATE TABLE "sellerprofile" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "user_id" INTEGER NOT NULL,
  "first_name" VARCHAR NOT NULL,
  "last_name" VARCHAR,
  "phone" "VARCHAR(20)" NOT NULL,
  "business_name" VARCHAR NOT NULL,
  "gst_number" VARCHAR,
  "fssai_license" VARCHAR,
  "bank_account_number" VARCHAR NOT NULL,
  "bank_ifsc" VARCHAR NOT NULL,
  "verification_status" verificationstatus NOT NULL,
  "rejection_reason" VARCHAR,
  "business_address_id" INTEGER NOT NULL
);

CREATE TABLE "address" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "address_line1" "VARCHAR(120)" NOT NULL,
  "address_line2" "VARCHAR(120)",
  "landmark" "VARCHAR(120)",
  "city" "VARCHAR(80)" NOT NULL,
  "state" "VARCHAR(80)" NOT NULL,
  "pincode" "VARCHAR(10)" NOT NULL,
  "country" "VARCHAR(60)" NOT NULL,
  "latitude" "DOUBLEPRECISION",
  "longitude" "DOUBLEPRECISION"
);

CREATE TABLE "customeraddress" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "customer_profile_id" INTEGER NOT NULL,
  "address_id" INTEGER NOT NULL,
  "label" VARCHAR,
  "is_default" BOOLEAN NOT NULL
);

CREATE TABLE "service" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "slug" VARCHAR NOT NULL,
  "icon_url" VARCHAR,
  "is_active" BOOLEAN NOT NULL,
  "sort_order" INTEGER NOT NULL
);

CREATE TABLE "service_translation" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "service_id" INTEGER NOT NULL,
  "language_code" languagecode NOT NULL,
  "name" VARCHAR NOT NULL,
  "description" VARCHAR
);

CREATE TABLE "category" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "service_id" INTEGER NOT NULL,
  "slug" VARCHAR NOT NULL,
  "sort_order" INTEGER NOT NULL
);

CREATE TABLE "category_translation" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "category_id" INTEGER NOT NULL,
  "language_code" languagecode NOT NULL,
  "name" VARCHAR NOT NULL,
  "description" VARCHAR
);

CREATE TABLE "subcategory" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "category_id" INTEGER NOT NULL,
  "slug" VARCHAR NOT NULL,
  "sort_order" INTEGER NOT NULL
);

CREATE TABLE "subcategory_translation" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "subcategory_id" INTEGER NOT NULL,
  "language_code" languagecode NOT NULL,
  "name" VARCHAR NOT NULL,
  "description" VARCHAR
);

CREATE TABLE "masterproduct" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "subcategory_id" INTEGER NOT NULL,
  "slug" VARCHAR NOT NULL,
  "image_url" VARCHAR
);

CREATE TABLE "masterproduct_translation" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "master_product_id" INTEGER NOT NULL,
  "language_code" languagecode NOT NULL,
  "name" VARCHAR NOT NULL,
  "description" VARCHAR NOT NULL
);

CREATE TABLE "store" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "name" VARCHAR NOT NULL,
  "is_active" BOOLEAN NOT NULL,
  "seller_profile_id" INTEGER NOT NULL,
  "address_id" INTEGER NOT NULL
);

CREATE TABLE "storeinventory" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "store_id" INTEGER NOT NULL,
  "product_id" INTEGER NOT NULL,
  "price" "DOUBLEPRECISION" NOT NULL,
  "stock" INTEGER NOT NULL,
  "is_available" BOOLEAN NOT NULL
);

CREATE TABLE "cart" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "customer_profile_id" INTEGER NOT NULL,
  "store_id" INTEGER NOT NULL
);

CREATE TABLE "cartitem" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "cart_id" INTEGER NOT NULL,
  "inventory_id" INTEGER NOT NULL,
  "quantity" INTEGER NOT NULL
);

CREATE TABLE "order" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "customer_profile_id" INTEGER NOT NULL,
  "store_id" INTEGER NOT NULL,
  "delivery_address_id" INTEGER NOT NULL,
  "status" orderstatus NOT NULL,
  "subtotal" "DOUBLEPRECISION" NOT NULL,
  "delivery_fee" "DOUBLEPRECISION" NOT NULL,
  "tax" "DOUBLEPRECISION" NOT NULL,
  "total" "DOUBLEPRECISION" NOT NULL,
  "placed_at" "TIMESTAMPTZ" NOT NULL
);

CREATE TABLE "orderitem" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "order_id" INTEGER NOT NULL,
  "inventory_id" INTEGER NOT NULL,
  "product_name_snapshot" VARCHAR NOT NULL,
  "unit_price_snapshot" "DOUBLEPRECISION" NOT NULL,
  "quantity" INTEGER NOT NULL,
  "line_total" "DOUBLEPRECISION" NOT NULL
);

CREATE TABLE "payment" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "order_id" INTEGER NOT NULL,
  "amount" "DOUBLEPRECISION" NOT NULL,
  "method" paymentmethod NOT NULL,
  "status" paymentstatus NOT NULL,
  "gateway_txn_id" VARCHAR,
  "paid_at" "TIMESTAMPTZ"
);

CREATE TABLE "delivery" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "order_id" INTEGER NOT NULL,
  "status" deliverystatus NOT NULL,
  "packed_at" "TIMESTAMPTZ",
  "dispatched_at" "TIMESTAMPTZ",
  "delivered_at" "TIMESTAMPTZ",
  "tracking_notes" VARCHAR
);

CREATE TABLE "review" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "updated_at" "TIMESTAMPTZ" NOT NULL,
  "customer_profile_id" INTEGER NOT NULL,
  "product_id" INTEGER,
  "store_id" INTEGER,
  "order_id" INTEGER,
  "rating" INTEGER NOT NULL,
  "comment" VARCHAR
);

CREATE TABLE "favorite" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "created_at" "TIMESTAMPTZ" NOT NULL,
  "customer_profile_id" INTEGER NOT NULL,
  "product_id" INTEGER NOT NULL
);

