COMMENT ON TABLE "language" IS 'Seed: en/English/English, hi/Hindi/हिन्दी, mr/Marathi/मराठी, gu/Gujarati/ગુજરાતી, pa/Punjabi/ਪੰਜਾਬੀ. languagecode enum: en, hi, mr, gu, pa.';

COMMENT ON TABLE "customeraddress" IS 'Partial unique index: CREATE UNIQUE INDEX uq_customeraddress_one_default ON customeraddress (customer_profile_id) WHERE is_default = true';

COMMENT ON TABLE "service" IS 'Top-level vertical: Groceries, Pharmacy, Restaurant, etc. Display name/description live in service_translation.';

COMMENT ON TABLE "order" IS 'Totals are intentionally denormalized for immutable financial history.';

COMMENT ON TABLE "review" IS 'CHECK ((product_id IS NOT NULL) != (store_id IS NOT NULL))';

